tool.command:
skesa
#set fqscan = "text" #if $jobtype.select == "fastq_fr" #set outname = $jobtype.fastq1.name #set bwalist = str($jobtype.fastq1) + " " + str($jobtype.fastq2) --fastq $jobtype.fastq1,$jobtype.fastq2 #if $jobtype.fastq1.is_of_type("fastq.gz") #set fqscan = "gz" #else if $jobtype.fastq1.is_of_type("fastqsanger.gz") #set fqscan = "gz" #end if #else if $jobtype.select == "fastq_pair" #set outname = $jobtype.coll.name #set bwalist = str($jobtype.coll.forward) + " " + str($jobtype.coll.reverse) --fastq $jobtype.coll.forward,$jobtype.coll.reverse #if $jobtype.coll.forward.is_of_type("fastq.gz") #set fqscan = "gz" #else if $jobtype.coll.forward.is_of_type("fastqsanger.gz") #set fqscan = "gz" #end if #end if
#set num_cores = 1
#if $options.select =="basic" --cores $num_cores --memory 8 #else if $options.select=="advanced" #if $options.cores #set num_cores = $options.cores --cores $options.cores #end if #if $options.memory --memory $options.memory #end if #if $options.hash_count --hash_count #end if #if $options.estimated_kmers --estimated_kmers $options.estimated.kmers #end if #if $options.skip --skip_bloom_filter #end if #if $options.kmer --kmer $options.kmer #end if #if $options.min_count --min_count $options.min_count #end if #if $options.max_kmer_count --max_kmer_count $options.max_kmer_count #end if #if $options.vector_percent --vector_percent $options.vector_percent #end if #if $options.insert_size --insert_size $options.insert.size #end if #if $options.steps --steps $options.steps #end if #if $options.fraction --fraction $options.fraction #end if #if $options.max_snp_len --max_snp_len $options.max_snp_len #end if #if $options.min_contig --min_contig $options.min_contig #end if #if $options.allow_snps --allow_snps #end if #end if
> ${outname}.fasta;
bwa index ${outname}.fasta; bwa mem -t $num_cores ${outname}.fasta ${bwalist} | python $__tool_directory__/median_size.py > insert.median;
mlst --nopath --threads $num_cores --datadir $mlst_databases.fields.path/pubmlst --blastdb $mlst_databases.fields.path/blast/mlst.fa #if $options.select=="advanced" #if $options.minid --minid $options.minid #end if #if $options.mincov --mincov $options.mincov #end if #if $options.minscore --minscore $options.minscore #end if #end if ${outname}.fasta > ${outname}.mlst_raw.tsv;
python $__tool_directory__/mlstAddFields.py ${outname}.mlst_raw.tsv $mlst_databases.fields.path/pubmlst > ${outname}.mlst.tsv;
python $__tool_directory__/run_fastq_scan.py --fastq ${bwalist} --out fq_out.tab --type ${fqscan};
python $__tool_directory__/sum_mlst.py --fasta ${outname}.fasta --mlst ${outname}.mlst.tsv --med insert.median --fqscan fq_out.tab --out sum_qc.txt

citations.citation:
 @UNPUBLISHED{Seemann2016,
 author = "Seemann T",
 title = "MLST: Scan contig files against PubMLST typing schemes",
 year = "2016",
 url = {https://github.com/tseemann/mlst}
}
